using UniswapSharp.Router;

namespace UniswapSharp.Testing.Router;

// Ported 1:1 from sdks/router-sdk/src/multicallExtended.test.ts
public class MulticallExtendedTests
{
    [Fact]
    public void WorksWithNoValidation()
    {
        Assert.Equal("0x01", MulticallExtended.EncodeMulticall("0x01"));
    }

    [Fact]
    public void WorksWithDeadlineAsString()
    {
        Assert.Equal(
            "",
            MulticallExtended.EncodeMulticall("0x01", "123"));
    }

    [Fact]
    public void WorksWithDeadlineAsNumber()
    {
        Assert.Equal(
            "",
            MulticallExtended.EncodeMulticall("0x01", 123));
    }

    [Fact]
    public void WorksWithPreviousBlockHash()
    {
        Assert.Equal(
            "",
            MulticallExtended.EncodeMulticall("0x01", "0xaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa"));
    }
}
